const body = $input.first().json.body || {};
const rawAction = String(body.action || '').trim();
const session_id = String(body.session_id || '').trim();
const message = String(body.message || '').trim();

// Ping для health-check со страницы платформы (любой action или message=ping)
if (message === 'ping' || rawAction === 'ping') {
  return [{ json: { valid: 0, error: 'pong', action: 'ping' } }];
}

if (!session_id) {
  return [{ json: { valid: 0, error: 'session_id обязательно' } }];
}
if (!/^[a-zA-Z0-9_-]+$/.test(session_id)) {
  return [{ json: { valid: 0, error: 'session_id содержит недопустимые символы' } }];
}

// token — bearer для аутентификации. ОБЯЗАТЕЛЕН для всех action-ов
// (auth-workflow выдаёт токен при login, фронт хранит в localStorage и
// шлёт в каждом запросе). Формат: 64 hex символа (32 байта random).
const token = String(body.token || '').trim();
if (!token) {
  return [{ json: { valid: 0, error: 'unauthorized', auth_required: true } }];
}
if (!/^[a-f0-9]{64}$/.test(token)) {
  return [{ json: { valid: 0, error: 'unauthorized', auth_required: true } }];
}





// Если action не указан, но есть message — это chat-agent шлёт через GigaChat.createChatAgent,
// дефолтим в 'query' чтобы AI обработал. Если ни action, ни message — это пинг или ошибка.
const action = rawAction || (message ? 'query' : '');

const ALLOWED = ['list', 'create', 'update', 'delete', 'query'];
if (!ALLOWED.includes(action)) {
  return [{ json: { valid: 0, error: 'Неизвестный action: ' + rawAction } }];
}

function safePriority(p) {
  const v = String(p || 'medium').toLowerCase();
  return ['low','medium','high'].includes(v) ? v : 'medium';
}
function safeDeadline(d) {
  if (!d) return null;
  const s = String(d).trim();
  if (!s) return null;
  if (!/^\d{4}-\d{2}-\d{2}$/.test(s)) return null;
  return s;
}
function safeStatus(s) {
  const v = String(s || '').toLowerCase();
  return ['active','completed'].includes(v) ? v : null;
}

const out = { valid: 1, action, session_id, token };

if (action === 'create') {
  const title = String(body.title || '').trim();
  if (!title) return [{ json: { valid: 0, error: 'title обязательно для create' } }];
  if (title.length > 500) return [{ json: { valid: 0, error: 'title слишком длинный (>500 символов)' } }];
  out.title = title;
  out.description = String(body.description || '').slice(0, 5000);
  out.priority = safePriority(body.priority);
  out.deadline = safeDeadline(body.deadline);
}

if (action === 'update') {
  const taskId = parseInt(body.id, 10);
  if (!Number.isInteger(taskId) || taskId < 1) {
    return [{ json: { valid: 0, error: 'id обязательно для update' } }];
  }
  out.task_id = taskId;
  // Если поле передано — обновляем; иначе оставляем NULL и SQL через COALESCE сохранит старое.
  out.title = body.title === undefined ? null : String(body.title).slice(0, 500);
  out.description = body.description === undefined ? null : String(body.description).slice(0, 5000);
  out.priority = body.priority === undefined ? null : safePriority(body.priority);
  out.deadline = body.deadline === undefined ? '__keep__' : safeDeadline(body.deadline);
  out.status = body.status === undefined ? null : safeStatus(body.status);
}

if (action === 'delete') {
  const taskId = parseInt(body.id, 10);
  if (!Number.isInteger(taskId) || taskId < 1) {
    return [{ json: { valid: 0, error: 'id обязательно для delete' } }];
  }
  out.task_id = taskId;
}

if (action === 'query') {
  if (!message) return [{ json: { valid: 0, error: 'Введите запрос для AI' } }];
  if (message.length > 5000) return [{ json: { valid: 0, error: 'Запрос слишком длинный' } }];
  out.message = message;
}

if (action === 'list') {
  const f = String(body.filter || 'active').toLowerCase();
  out.filter = ['active','completed','all'].includes(f) ? f : 'active';
}

return [{ json: out }];

const __item = $input.first();
const __data = __item && __item.json ? __item.json : null;

function __extractErr(e) {
  if (!e) return '';
  if (typeof e === 'string') return e;
  if (e.message) return String(e.message);
  if (e.detail) return String(e.detail);
  try { return JSON.stringify(e); } catch (_) { return String(e); }
}
function __makeError(msg) {
  const isMissing = /does not exist|relation "planner_tasks"|relation \\"planner_tasks\\"/i.test(msg);
  return [{ json: { response: 'error', error: isMissing
    ? 'Таблица planner_tasks не создана в БД. Запустите База данных/planner-schema.sql (см. Планировщик/README.md).'
    : 'Ошибка БД: ' + msg
  }}];
}

// Кейс 1: error в .error поле (стандартный n8n format)
if (__data && __data.error) {
  return __makeError(__extractErr(__data.error));
}
// Кейс 2: input вообще отсутствует (onError + не выдало item)
if (!__item || !__data) {
  return __makeError('SQL-нода не вернула данные. Возможно таблица planner_tasks отсутствует.');
}
// Список задач: SELECT мог вернуть несколько строк
const items = $input.all();
// Проверка ошибки на ПЕРВОМ item (если есть)
if (items.length && items[0].json && items[0].json.error) {
  return __makeError(__extractErr(items[0].json.error));
}
const tasks = items.map(i => (i && i.json) || {}).filter(t => t && t.id);
return [{ json: { response: 'ok', tasks: tasks } }];

