return [{ json: { response: 'ok', task: __data } }];

// Готовим параметры под UPDATE: deadline отдельно обрабатываем чтобы
// разрешить и null (юзер хочет убрать дедлайн), и оставить старый (если поле не передано).
const v = $input.first().json;
const keep_deadline = v.deadline === '__keep__';
const new_deadline = keep_deadline ? null : (v.deadline || null);
return [{ json: {
  ...v,
  _keep_deadline: keep_deadline,
  _new_deadline: new_deadline,
} }];

