return [{ json: { response: __data && __data.id ? 'ok' : 'not_found', id: __data ? __data.id : null } }];

// Собираем активные задачи в текстовый список для подачи в LLM.
// Также пробрасываем session_id и message из исходного запроса.
const tasks = $input.all().map(i => i.json).filter(r => r && r.title);
const src = $('Token result').first().json;
const today = new Date().toISOString().slice(0, 10);

function fmtTask(t, idx) {
  const prio = t.priority === 'high' ? 'высокий' : t.priority === 'low' ? 'низкий' : 'средний';
  const dl = t.deadline ? ` (до ${t.deadline})` : '';
  const desc = t.description ? `\n   Описание: ${t.description}` : '';
  return `${idx+1}. [Приоритет: ${prio}${dl}] ${t.title}${desc}`;
}

const taskList = tasks.length === 0
  ? '(активных задач пока нет)'
  : tasks.map(fmtTask).join('\n');

const systemPrompt = `Ты — планировщик задач GigaChat. Помогаешь пользователю ${src.username} организовать дела.

Сегодня: ${today}

Текущие активные задачи пользователя ${src.username}:
${taskList}

Правила:
- Отвечай конкретно. План — это «понедельник: задача А; вторник: задача B; ...».
- Уважай приоритеты: высокий > средний > низкий.
- Уважай дедлайны: задача с дедлайном раньше — раньше в плане.
- Если задача просрочена (дедлайн < сегодня) — выдели её ⚠.
- НЕ выдумывай задачи которых нет в списке. Работай только с тем что выше.
- Если запрос не про планирование (например «спасибо», «привет») — отвечай по-человечески коротко.
- Не используй markdown-заголовки (###), пиши обычным текстом или с дефисами.
- На русском, кратко.`;

return [{ json: {
  session_id: src.session_id,
  message: src.message,
  systemPrompt: systemPrompt,
  task_count: tasks.length,
} }];

const raw = $input.first().json;
if (raw.error) {
  return [{ json: { response: 'LLM недоступен. Попробуйте позже.', _save: false } }];
}
const text = raw && raw.output && raw.output[0] && raw.output[0].content && raw.output[0].content[0] && raw.output[0].content[0].text;
if (!text) {
  return [{ json: { response: 'Пустой ответ от LLM.', _save: false } }];
}
const src = $('Валидация').first().json;
return [{ json: {
  response: text.trim(),
  _save: true,
  session_id: src.session_id,
  user_message: src.message,
} }];

// Сохранение могло не пройти (БД недоступна) — это не страшно, текст у нас есть.
// Главное — вернуть ответ юзеру.
const src = $('Извлечь ответ').first().json;
return [{ json: { response: src.response } }];

// Token verification result. Если SELECT вернул user_id — токен валидный,
// прокидываем дальше user_id (int) и username (string) для AI-промпта.
// Если пусто — auth_required, фронт перенаправит на login.
const item = $input.first();
const data = item && item.json ? item.json : null;
const src = $('Валидация').first().json;

if (!data || !data.user_id) {
  return [{ json: { token_valid: false, response: 'error', error: 'unauthorized', auth_required: true } }];
}

// Прокидываем все исходные поля из валидации + user_id/username из токена.
return [{ json: {
  ...src,
  token_valid: true,
  user_id: data.user_id,
  username: data.username,
}}];
